import requests

# RabbitMQ Management API credentials and URL
rabbitmq_url = 'http://localhost:15672'
admin_user = 'admin'
admin_password = 'password'

# List of vhosts, users, and permissions
vhosts_users_permissions = [
    {'vhost': '/app1', 'user': 'user1', 'password': 'pass1', 'permissions': ['read', 'write', 'configure']},
    {'vhost': '/app2', 'user': 'user2', 'password': 'pass2', 'permissions': ['read', 'write', 'configure']}
]

# Create vhosts, users, and set permissions
for item in vhosts_users_permissions:
    vhost = item['vhost']
    user = item['user']
    password = item['password']
    permissions = item['permissions']

    # Create vhost
    requests.put(f'{rabbitmq_url}/api/vhosts/{vhost}', auth=(admin_user, admin_password), json={})

    # Add user and set password
    requests.put(f'{rabbitmq_url}/api/users/{user}', auth=(admin_user, admin_password), json={'password': password})

    # Set permissions for the vhost
    requests.put(f'{rabbitmq_url}/api/permissions/{vhost}/{user}', auth=(admin_user, admin_password), json={'configure': f'.*:{vhost}.*', 'write': f'.*:{vhost}.*', 'read': f'.*:{vhost}.*'})

print("Vhosts, users, and permissions created successfully.")